import{_ as e,o as a,c as l,a7 as r}from"./chunks/framework.C5fSpjcB.js";const p=JSON.parse('{"title":"繁殖狂乱（Proliferation）","description":"","frontmatter":{},"headers":[],"relativePath":"ja/modes/proliferation.md","filePath":"ja/modes/proliferation.md","lastUpdated":1775394001000}'),i={name:"ja/modes/proliferation.md"};function o(n,t,d,s,h,c){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="繁殖狂乱-proliferation" tabindex="-1">繁殖狂乱（Proliferation） <a class="header-anchor" href="#繁殖狂乱-proliferation" aria-label="Permalink to &quot;繁殖狂乱（Proliferation）&quot;">​</a></h1><p><strong>繁殖狂乱</strong>はウェーブ制のサバイバルモードです。次々と押し寄せる敵の群れを撃退し、生き残った波数に応じて報酬を獲得します。</p><h2 id="基本ルール" tabindex="-1">基本ルール <a class="header-anchor" href="#基本ルール" aria-label="Permalink to &quot;基本ルール&quot;">​</a></h2><ul><li>ウェーブ（波）制で敵が次々と出現</li><li>ウェーブが進むごとに敵の数・強さが増加</li><li>全滅するか撤退するまで継続</li><li>到達ウェーブに応じて報酬を獲得</li></ul><h2 id="ウェーブ構成" tabindex="-1">ウェーブ構成 <a class="header-anchor" href="#ウェーブ構成" aria-label="Permalink to &quot;ウェーブ構成&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">ウェーブ</th><th style="text-align:left;">特徴</th></tr></thead><tbody><tr><td style="text-align:center;">1〜5</td><td style="text-align:left;">通常の雑魚敵。ウォームアップ</td></tr><tr><td style="text-align:center;">6〜10</td><td style="text-align:left;">エリート敵が混在。編成力が試される</td></tr><tr><td style="text-align:center;">11〜15</td><td style="text-align:left;">ミニボスが出現。高難度</td></tr><tr><td style="text-align:center;">16〜20</td><td style="text-align:left;">大量の敵+ボス級。最高難度</td></tr><tr><td style="text-align:center;">21〜</td><td style="text-align:left;">エンドレス。ランキング用</td></tr></tbody></table><h2 id="攻略のコツ" tabindex="-1">攻略のコツ <a class="header-anchor" href="#攻略のコツ" aria-label="Permalink to &quot;攻略のコツ&quot;">​</a></h2><ol><li><strong>範囲攻撃が有効</strong> — 大量の敵を一掃できるカードを優先</li><li><strong>持久力が重要</strong> — 回復・シールド手段を確保</li><li><strong>狂気バーストの温存</strong> — ミニボスウェーブに合わせてバーストを温存</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>繁殖狂乱は血肉界域の自傷ギミックと相性が良いです。高HPを活かした長期戦が有効です。</p></div><h2 id="報酬" tabindex="-1">報酬 <a class="header-anchor" href="#報酬" aria-label="Permalink to &quot;報酬&quot;">​</a></h2><p><em>準備中...</em></p><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./combat.html">戦闘システム</a></li><li><a href="./../awakeners/team-building.html">編成ガイド</a></li><li><a href="./">ゲームモード一覧</a></li></ul>',13)])])}const m=e(i,[["render",o]]);export{p as __pageData,m as default};
